// Tenacity 4.0 - KillAura (track entity teleport for target pos)
if (event.getPacket() instanceof S18PacketEntityTeleport) {
  S18PacketEntityTeleport s18 =
    (S18PacketEntityTeleport) event.getPacket();
  int entityId = s18.getEntityId();
  double x = s18.getX() / 32.0;
  double y = s18.getY() / 32.0;
  double z = s18.getZ() / 32.0;
  updateTargetPosition(entityId, x, y, z);
}
